INSERT INTO "public"."dev_prayers" ("lesson_id", "role", "text_content", "display_order") VALUES
('007e8630-e9e5-4d72-b59b-b1a57f96c090', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos que a Tua aprovação vale mais do que o aplauso de qualquer grupo. Dá-nos a coragem necessária para sermos exemplos de retidão.', 1),
('007e8630-e9e5-4d72-b59b-b1a57f96c090', 'Filho', 'Deus, dá-me forças para ser corajoso na escola e entre meus amigos. Ajuda-me a lembrar que Tu estás comigo, mesmo quando preciso escolher o caminho mais difícil.', 2),
('007e8630-e9e5-4d72-b59b-b1a57f96c090', 'Juntos', 'Pai, ajuda nossa família a permanecer de pé diante das pressões deste mundo. Que a nossa maior honra seja sempre Te obedecer.', 3),
('00ff9dc6-f0df-4755-ab45-3336f120839e', 'Individual', 'Senhor, ajuda-me a edificar convicções tão firmes que nenhum barulho deste mundo possa me desviar. Que minha fidelidade não dependa das circunstâncias, mas da Tua verdade que habita em mim. Que eu aprenda a ser fiel no secreto para permanecer inabalável diante da multidão. Amém.', 1),
('0118f762-7f79-4ccc-a111-dc130891a1a9', 'Pai', 'Senhor, ajuda-me a ser um pai que acolhe com amor e bondade. Que meus ouvidos estejam sempre prontos para ouvir um coração sincero.', 1),
('0118f762-7f79-4ccc-a111-dc130891a1a9', 'Filho', 'Deus, dá-me coragem para enxergar meus erros com clareza. Que eu saiba voltar pelo caminho da verdade e da obediência.', 2),
('0118f762-7f79-4ccc-a111-dc130891a1a9', 'Juntos', 'Pai, faz da nossa família um lugar de restauração e firmeza. Que a nossa confiança em Ti seja a base de todas as nossas escolhas.', 3),
('01d8a7a3-46a4-4783-ba2d-adcf08894f4c', 'Pai', 'Senhor, dá a nossos filhos a coragem de Sadraque, Mesaque e Abednego. Que o temor ao Teu nome seja maior que qualquer medo dos outros.', 1),
('01d8a7a3-46a4-4783-ba2d-adcf08894f4c', 'Filho', 'Pai, ajuda-me a decidir hoje por Ti. Que eu não me dobre às vontades do mundo, mesmo quando ninguém estiver me vendo.', 2),
('01d8a7a3-46a4-4783-ba2d-adcf08894f4c', 'Juntos', 'Que nossa família seja um testemunho de fé inabalável. Que em todas as escolhas, o Senhor seja sempre o nosso primeiro lugar.', 3),
('01e7f6cf-156e-409b-954e-4801d2323710', 'Pai', 'Senhor, ajuda-me a guiar meu filho com sabedoria, lembrando que a verdadeira direção vem do Teu trono.', 1),
('01e7f6cf-156e-409b-954e-4801d2323710', 'Filho', 'Deus, ensina-me a confiar em Ti quando não sei qual caminho escolher e dá-me um coração humilde.', 2),
('01e7f6cf-156e-409b-954e-4801d2323710', 'Juntos', 'Que a nossa casa seja um lugar onde o Teu conselho é sempre a primeira regra, agora e sempre.', 3),
('01f8e0aa-c8c7-43d8-8b29-5518af705cbd', 'Pai', 'Papai do Céu, ensina nossos corações a serem atentos e bondosos. Ajuda-nos a amar o próximo como Tu nos amas.', 1),
('01f8e0aa-c8c7-43d8-8b29-5518af705cbd', 'Filho', 'Jesus, coloca bondade no meu coração hoje. Que eu possa ajudar quem estiver perto de mim.', 2),
('01f8e0aa-c8c7-43d8-8b29-5518af705cbd', 'Juntos', 'Queremos ser como o bom samaritano, sempre prontos a cuidar uns dos outros. Amém.', 3),
('021ea3fc-a09b-416f-b53e-77b497972064', 'Pai', 'Senhor, dá-nos a coragem e a sabedoria que Daniel teve para honrar Teus mandamentos. Ajuda-nos a sermos firmes em nossas escolhas.', 1),
('021ea3fc-a09b-416f-b53e-77b497972064', 'Filho', 'Deus, ajuda-me a não ter medo de fazer o que é certo, mesmo quando meus amigos pensam de um jeito diferente.', 2),
('021ea3fc-a09b-416f-b53e-77b497972064', 'Juntos', 'Que nossa família caminhe sempre em Tua verdade, escolhendo Tua vontade acima de qualquer pressão. Amém.', 3),
('0250a559-6c26-43be-9c9c-b52682856cd4', 'Pai', 'Senhor, ensina nossos filhos que o Teu amor é maior que qualquer erro. Ajuda-nos a sermos acolhedores como o pai da história.', 1),
('0250a559-6c26-43be-9c9c-b52682856cd4', 'Filho', 'Papai do Céu, me ajude a ser obediente e, quando eu errar, me dê coragem para pedir perdão logo.', 2),
('0250a559-6c26-43be-9c9c-b52682856cd4', 'Juntos', 'Obrigado por nos amar sempre. Que nossa casa seja sempre um lugar de festa e perdão!', 3),
('02e20acb-694d-483a-94f7-8008c40ab5b3', 'Pai', 'Senhor, dá a nós a coragem de sermos sempre verdadeiros um com o outro. Que nossa casa seja um lugar de confiança e proteção.', 1),
('02e20acb-694d-483a-94f7-8008c40ab5b3', 'Filho', 'Pai do céu, ajuda-me a não ter medo de dizer a verdade, mesmo quando for difícil. Que a minha lealdade seja como a de Jônatas.', 2),
('02e20acb-694d-483a-94f7-8008c40ab5b3', 'Juntos', 'Que a nossa família caminhe sempre na luz da Tua verdade. Amém.', 3),
('02ebe8aa-dcdf-4b1b-9d71-14d6c9ae85b9', 'Pai', 'Senhor, ajuda-nos a lembrar das vezes que nos livraste e a confiar em Tua força. Que sejamos corajosos diante de qualquer desafio.', 1),
('02ebe8aa-dcdf-4b1b-9d71-14d6c9ae85b9', 'Filho', 'Deus, tira o medo que me faz agir errado. Dá-me forças para ser fiel a Ti, mesmo quando for difícil.', 2),
('02ebe8aa-dcdf-4b1b-9d71-14d6c9ae85b9', 'Juntos', 'Pai, que a Tua presença seja o nosso escudo contra todos os gigantes. Amém.', 3),
('0326d84c-78d9-4ffd-a91e-942a39e62463', 'Pai', 'Senhor, ajuda-nos a criar um lar onde a verdade seja sempre bem-vinda. Dá-nos sabedoria para perdoar com a mesma prontidão que o pai desta história.', 1),
('0326d84c-78d9-4ffd-a91e-942a39e62463', 'Filho', 'Deus, ajuda-me a ter a coragem de assumir meus erros sem dar desculpas. Ensina-me a ser honesto quando eu falhar com as pessoas que amo.', 2),
('0326d84c-78d9-4ffd-a91e-942a39e62463', 'Juntos', 'Pai, obrigado porque o Teu perdão é sempre maior que o nosso erro. Guia nossos passos hoje no caminho da verdade e da prudência.', 3),
('0349b994-7c9a-44dc-98da-770fb6170e39', 'Pai', 'Senhor, ajuda-nos a valorizar a verdade acima de qualquer vantagem imediata. Que nossa família seja firme em honrar Teu nome em tudo o que fazemos.', 1),
('0349b994-7c9a-44dc-98da-770fb6170e39', 'Filho', 'Deus, dá-me coragem para fugir do que é errado, mesmo quando parece ser o caminho mais fácil. Ensina-me a ser fiel a Ti no segredo.', 2),
('0349b994-7c9a-44dc-98da-770fb6170e39', 'Juntos', 'Que a Tua presença seja a nossa maior recompensa. Ajuda-nos a viver com transparência e integridade em todos os nossos dias.', 3),
('0350b006-4753-4af0-add5-ad6ec56f7897', 'Pai', 'Papai do Céu, obrigado porque o Senhor cuida de nós com tanto amor. Ajuda-nos a confiar sempre no Teu cuidado.', 1),
('0350b006-4753-4af0-add5-ad6ec56f7897', 'Filho', 'Jesus, tira o medo do meu coração e me ajuda a lembrar que sou precioso para Ti. Cuida de mim como cuidas dos passarinhos.', 2),
('0350b006-4753-4af0-add5-ad6ec56f7897', 'Juntos', 'Nós confiamos em Ti, Senhor! Sabemos que o Teu amor nos guarda agora e sempre.', 3),
('03bc7b03-39ef-464a-9e88-85ebde1338fd', 'Pai', 'Senhor, ensina-nos a confiar em Ti como Sadraque, Mesaque e Abednego confiaram. Dá-nos um coração valente para Te obedecer sempre.', 1),
('03bc7b03-39ef-464a-9e88-85ebde1338fd', 'Filho', 'Papai do Céu, ajuda-me a ser obediente mesmo quando tiver medo. Fica comigo hoje em todos os lugares onde eu estiver.', 2),
('03bc7b03-39ef-464a-9e88-85ebde1338fd', 'Juntos', 'Obrigado, Deus, porque o Senhor está sempre pertinho de nós. Ajuda-nos a sermos amigos fiéis da Tua vontade!', 3),
('03bda273-259e-4620-a677-9059d58c43c0', 'Individual', 'Senhor, ajuda-me a compreender que a minha verdadeira grandeza reside na disposição de servir. Livra-me da necessidade de reconhecimento e do orgulho que me impede de descer ao nível do meu próximo. Que minha segurança em Ti seja a fonte constante da minha generosidade, tornando meu serviço um reflexo fiel da Tua própria natureza. Amém.', 1),
('04973b6e-fc53-4ccc-91ca-65553e6a2df3', 'Pai', 'Senhor, dá a este meu filho a coragem de ser fiel ao Senhor, mesmo quando estiver sozinho. Que a Tua verdade seja o seu guia seguro.', 1),
('04973b6e-fc53-4ccc-91ca-65553e6a2df3', 'Filho', 'Pai do Céu, ajuda-me a não ter medo de ser diferente. Dá-me forças para escolher o que agrada a Ti todos os dias.', 2),
('04973b6e-fc53-4ccc-91ca-65553e6a2df3', 'Juntos', 'Que a nossa família permaneça firme na Tua Palavra. Que nunca nos curvemos diante de nada que ocupe o Teu lugar.', 3),
('04afc16f-30e4-4d2d-a0cc-b40ddeb1b99a', 'Pai', 'Senhor, ajuda-nos a confiar no Teu tempo. Que nossas escolhas privadas sejam tão íntegras quanto as públicas.', 1),
('04afc16f-30e4-4d2d-a0cc-b40ddeb1b99a', 'Filho', 'Deus, dá-me forças para ser paciente nas dificuldades. Ensina-me a construir um caráter que honre o Teu nome.', 2),
('04afc16f-30e4-4d2d-a0cc-b40ddeb1b99a', 'Juntos', 'Pai, formai nossos corações pela Tua Palavra. Que a paciência nos prepare para os propósitos que tens para nós.', 3),
('051a22c0-1779-4e15-b0f7-2165f287fd3b', 'Individual', 'Senhor, dá-me sabedoria para não deixar que a aparência das coisas guie meus passos. Que a Tua Palavra seja o filtro real de minhas decisões, para que eu não troque a integridade pelo conforto ilusório. Livra-me de escolhas precipitadas e guia meu caminho segundo a Tua justiça.', 1),
('05fa1f1f-4b08-4143-b58b-d5a55f45a554', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos o valor de ter limites. Que possamos ser modelos de equilíbrio em nossas próprias escolhas.', 1),
('05fa1f1f-4b08-4143-b58b-d5a55f45a554', 'Filho', 'Pai do Céu, dá-me sabedoria para saber a hora de parar. Que eu consiga controlar meus impulsos mesmo quando algo parece muito bom.', 2),
('05fa1f1f-4b08-4143-b58b-d5a55f45a554', 'Juntos', 'Que a nossa casa seja um lugar de temperança e moderação. Ajuda-nos a buscar o que é certo, honrando a Ti em cada decisão.', 3),
('063fcc61-844d-426c-a4ba-51d71885bc65', 'Pai', 'Senhor, ajuda-nos a não esquecer quem nos dá cada fôlego e provisão diária. Que nossos filhos aprendam a valorizar cada bênção recebida.', 1),
('063fcc61-844d-426c-a4ba-51d71885bc65', 'Filho', 'Deus, perdoa meu esquecimento e minha falta de atenção. Ensina-me a parar meu corre-corre para Te adorar e honrar meus pais.', 2),
('063fcc61-844d-426c-a4ba-51d71885bc65', 'Juntos', 'Pai, que nossa família seja sempre marcada por corações gratos e obedientes. Que o nosso ''obrigado'' seja sincero e constante todos os dias.', 3),
('064ffd33-3d00-400a-89f6-413481cd24a9', 'Pai', 'Senhor, ajuda-nos a vigiar o que guardamos em nossa mente e coração. Que possamos ensinar um ao outro o caminho da integridade.', 1),
('064ffd33-3d00-400a-89f6-413481cd24a9', 'Filho', 'Pai Celestial, perdoa-me pelas vezes em que olho para o mal. Ajuda-me a manter meus pés no caminho certo, mesmo quando ninguém me vê.', 2),
('064ffd33-3d00-400a-89f6-413481cd24a9', 'Juntos', 'Deus, guia nossas escolhas e fortalece nossa família para honrar o Teu nome. Que a Tua verdade seja a nossa única medida.', 3),
('066b9005-c768-4e5d-ba82-6113548c471e', 'Pai', 'Senhor, dá ao meu filho a coragem de Daniel para manter os teus valores, mesmo quando for difícil. Que a Tua lei seja o guia do seu coração em todo lugar.', 1),
('066b9005-c768-4e5d-ba82-6113548c471e', 'Filho', 'Deus, ajuda-me a ser fiel nas escolhas pequenas e silenciosas do meu dia a dia. Que o meu caráter seja firme e honre o Teu nome em tudo.', 2),
('066b9005-c768-4e5d-ba82-6113548c471e', 'Juntos', 'Pai, fortalece nossa família para sermos íntegros diante de Ti. Que nossa vida sempre reflita a verdade, seja em casa ou diante do mundo.', 3),
('067a74c9-e934-45d7-891a-8430c070263a', 'Individual', 'Senhor, ajuda-me a manter os olhos na Tua fidelidade quando as circunstâncias parecerem gigantes e o medo tentar ditar o meu caminho. Concede-me a paciência necessária para não ceder à pressão do ambiente, fortalecendo minha integridade e a firmeza das minhas decisões hoje. Amém.', 1),
('06866db1-664a-4752-9f34-c09a17397119', 'Pai', 'Senhor, dá ao meu filho a coragem de ser fiel a Ti, mesmo quando o mundo ao redor exigir o contrário. Que a Tua verdade seja o norte das nossas decisões diárias.', 1),
('06866db1-664a-4752-9f34-c09a17397119', 'Filho', 'Pai do céu, ajuda-me a não ter medo de dizer não quando o grupo me pressionar a fazer o que Te desagrada. Que eu seja firme como foram os três jovens hebreus.', 2),
('06866db1-664a-4752-9f34-c09a17397119', 'Juntos', 'Deus, ajuda nossa família a buscar Tua aprovação acima de qualquer popularidade. Que sejamos sempre um testemunho da Tua verdade em meio a esta geração.', 3),
('069dd0aa-aab6-412b-8c48-b45c0fec6dbe', 'Individual', 'Senhor, concede-me a sabedoria de Daniel para manter minha integridade em meio às pressões deste mundo. Que a minha convicção não se transforme em orgulho, mas em um testemunho de fidelidade prática. Ajuda-me a agir com prudência, discernimento e coragem, escolhendo sempre o caminho que honra a Tua vontade em vez da conveniência imediata. Amém.', 1),
('06e8856e-baa5-4d79-8b40-f1e2905cee1b', 'Pai', 'Senhor, ajuda-nos a educar nossos filhos com a firmeza de quem teme a Ti. Que possamos ser exemplo de integridade em nossa própria casa.', 1),
('06e8856e-baa5-4d79-8b40-f1e2905cee1b', 'Filho', 'Deus, dá-me coragem para não me dobrar diante das pressões do mundo. Que eu prefira a Tua aprovação acima de tudo.', 2),
('06e8856e-baa5-4d79-8b40-f1e2905cee1b', 'Juntos', 'Pai, que nossa família seja conhecida por nossa fidelidade. Que Teu nome seja honrado em nossas escolhas todos os dias.', 3),
('070975a7-8a5a-47ea-bc04-1f27b41a1db8', 'Pai', 'Pai do Céu, obrigado por seres nosso refúgio. Ajuda-nos a confiar sempre em Ti.', 1),
('070975a7-8a5a-47ea-bc04-1f27b41a1db8', 'Filho', 'Querido Deus, ouve o meu coração como ouviste o de Ana. Estou feliz por conversar contigo!', 2),
('070975a7-8a5a-47ea-bc04-1f27b41a1db8', 'Juntos', 'Obrigado, Senhor, por nos unires em oração. Tu és o nosso grande e bom amigo.', 3),
('076f7a51-f2ac-40e8-a078-437288dcc2b1', 'Pai', 'Senhor, ajuda meu filho a ter a coragem de Daniel para permanecer fiel aos Teus mandamentos. Que a Tua voz seja mais alta que qualquer pressão externa.', 1),
('076f7a51-f2ac-40e8-a078-437288dcc2b1', 'Filho', 'Deus, dá-me sabedoria para escolher o que é certo, mesmo quando meus amigos pensam de forma diferente. Ensina-me a Te honrar em todas as minhas atitudes.', 2),
('076f7a51-f2ac-40e8-a078-437288dcc2b1', 'Juntos', 'Pai, que nossa família seja um reflexo da Tua verdade. Que possamos sempre escolher o Teu caminho acima da aprovação do mundo.', 3),
('078527d5-7a64-4c37-8e6e-b2ae27a963a2', 'Pai', 'Papai do Céu, ensina-nos a confiar em Ti como a viúva confiou. Que nossas mãos estejam sempre prontas para abençoar.', 1),
('078527d5-7a64-4c37-8e6e-b2ae27a963a2', 'Filho', 'Jesus, ajuda-me a repartir meus brinquedos com alegria. Quero que meu coração seja generoso como o Teu.', 2),
('078527d5-7a64-4c37-8e6e-b2ae27a963a2', 'Juntos', 'Obrigado por tudo o que nos dás. Que nossa casa seja sempre um lugar de partilha e amor!', 3),
('07aca7f3-80e4-4823-aa46-8481109fab15', 'Pai', 'Papai do Céu, ajuda meu filho a entender que o respeito é um tesouro precioso. Que ele aprenda a tratar todos ao seu redor com o mesmo amor que o Senhor nos dá.', 1),
('07aca7f3-80e4-4823-aa46-8481109fab15', 'Filho', 'Papai do Céu, ajuda-me a ser uma criança educada e bondosa. Que as minhas palavras e ações mostrem que eu quero honrar o Teu nome todos os dias.', 2),
('07aca7f3-80e4-4823-aa46-8481109fab15', 'Juntos', 'Querido Deus, abençoa a nossa família para que sejamos conhecidos pelo amor. Que o nosso exemplo reflita a Tua luz em tudo o que fizermos.', 3),
('07be85b8-8821-4cd5-a63d-e011e10e9403', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos a terem coragem como Daniel. Dá-nos sabedoria para guiar seus passos em Tua verdade.', 1),
('07be85b8-8821-4cd5-a63d-e011e10e9403', 'Filho', 'Papai do Céu, me ajude a ser corajoso como Daniel. Quero sempre escolher o que Te deixa feliz.', 2),
('07be85b8-8821-4cd5-a63d-e011e10e9403', 'Juntos', 'Obrigado, Deus, por estares sempre conosco. Ajuda-nos a sermos fortes e fiéis ao Senhor todos os dias.', 3),
('07e30633-bcd3-4e25-a385-90faf890a0c7', 'Pai', 'Senhor, ajuda-nos a ser firmes como Josué na nossa fé. Que nossa casa seja um testemunho da Tua verdade.', 1),
('07e30633-bcd3-4e25-a385-90faf890a0c7', 'Filho', 'Deus, dá-me coragem para escolher o que é certo, mesmo quando ninguém estiver olhando. Ensina-me a ser fiel a Ti.', 2),
('07e30633-bcd3-4e25-a385-90faf890a0c7', 'Juntos', 'Pai, decidimos servir apenas ao Senhor em todas as nossas escolhas. Guia os nossos passos hoje e sempre.', 3),
('08111499-2ee7-4ba3-b12c-9720c411ae7c', 'Pai', 'Senhor, ajuda-nos a ter um coração bondoso e humilde como o Teu. Ensina-nos a cuidar uns dos outros todos os dias.', 1),
('08111499-2ee7-4ba3-b12c-9720c411ae7c', 'Filho', 'Papai do céu, quero aprender a dividir meus brinquedos e colocar os meus amigos na frente. Ajuda-me a ser um pequeno servo.', 2),
('08111499-2ee7-4ba3-b12c-9720c411ae7c', 'Juntos', 'Obrigado, Jesus, pelo Teu exemplo de amor. Queremos caminhar contigo sempre e sermos gentis como Tu és!', 3),
('0884f7ce-dfe9-4b77-89e9-6757a27f534f', 'Individual', 'Senhor, capacita-me a exercer autoridade através do serviço. Que minha vontade esteja alinhada à Tua e que meu agir não dependa de aplausos, mas de uma fidelidade inabalável a Ti. Concede-me a clareza de propósito necessária para servir com excelência, sem buscar reconhecimento próprio, mantendo minha integridade e autogoverno diante de qualquer circunstância. Amém.', 1),
('08bd855f-cc01-4de5-aa8f-c8b86f1a53a1', 'Individual', 'Senhor, ajuda-me a manter os olhos firmes na obra que colocaste em minhas mãos. Dá-me a disciplina necessária para não ceder às distrações e o autogoverno para investir meu tempo naquilo que glorifica o Teu nome. Que a minha dedicação não seja passageira, mas constante e fiel até o fim. Amém.', 1),
('0900a274-1300-4389-a47a-d5b57f2cb062', 'Pai', 'Senhor, ensina-nos a abandonar o orgulho que busca sempre estar acima dos outros. Ajuda-me a ser um exemplo de servo em nossa casa.', 1),
('0900a274-1300-4389-a47a-d5b57f2cb062', 'Filho', 'Deus, tira do meu coração o desejo de querer ser o centro das atenções na escola. Dá-me um espírito humilde para ajudar meus amigos sem pedir nada em troca.', 2),
('0900a274-1300-4389-a47a-d5b57f2cb062', 'Juntos', 'Pai, que nossas atitudes glorifiquem o Teu nome e que o nosso servir seja um reflexo do amor de Jesus. Amém.', 3),
('09b13b2c-2700-4785-bc5b-284c1d26c5f3', 'Pai', 'Senhor, ajuda-nos a discernir o que é essencial em meio à correria. Que nossa casa seja um lugar de paz e não apenas de tarefas.', 1),
('09b13b2c-2700-4785-bc5b-284c1d26c5f3', 'Filho', 'Jesus, ensina-me a sentar aos Teus pés e ouvir Tua voz. Que eu não me deixe levar pelas distrações que me afastam de Ti.', 2),
('09b13b2c-2700-4785-bc5b-284c1d26c5f3', 'Juntos', 'Pai, ajuda-nos a priorizar o que é eterno. Que a Tua presença seja sempre a nossa escolha principal hoje.', 3),
('09c23206-adc6-41cf-9e65-5b48826f9c4a', 'Pai', 'Pai do Céu, obrigado por seres sempre o Pai que nos espera de braços abertos. Ensina o nosso coração a ser valente na verdade.', 1),
('09c23206-adc6-41cf-9e65-5b48826f9c4a', 'Filho', 'Papai do Céu, perdoa quando eu erro ou tento esconder o que fiz. Quero ser sempre honesto e voltar para o Teu carinho.', 2),
('09c23206-adc6-41cf-9e65-5b48826f9c4a', 'Juntos', 'Agradecemos porque o Teu amor é maior que qualquer erro nosso. Ajuda-nos a viver sempre na Tua luz, amém!', 3),
('09c73731-c23e-4aa0-b27d-0039b62e8dd3', 'Individual', 'Senhor, capacita-me a enxergar as feridas do passado com a clareza da Tua soberania. Que o meu coração não seja guiado pelo desejo de justiça própria, mas pelo Teu exemplo de misericórdia. Concede-me a força necessária para soltar o peso da mágoa e caminhar em liberdade, mantendo a integridade em meus relacionamentos e a fidelidade aos Teus caminhos. Amém.', 1),
('0a97e21b-dff8-4bef-94b6-1f46fd651716', 'Pai', 'Senhor, dá a este meu filho a coragem de ser honesto, mesmo quando for difícil. Que ele aprenda que nossa casa é sempre um lugar de acolhimento e perdão.', 1),
('0a97e21b-dff8-4bef-94b6-1f46fd651716', 'Filho', 'Deus, ajuda-me a não ter medo de pedir desculpas quando eu errar. Dá-me forças para escolher o caminho certo, mesmo se meus amigos não entenderem.', 2),
('0a97e21b-dff8-4bef-94b6-1f46fd651716', 'Juntos', 'Pai, obrigado porque o Teu perdão é sempre maior que nossas falhas. Que sejamos uma família que sempre volta para o Senhor.', 3),
('0af51922-e35f-493c-b212-68734b0a18ad', 'Individual', 'Senhor, ajuda-me a manter a firmeza de Daniel em todas as minhas decisões. Que o meu caráter seja sempre condizente com a Tua vontade, sem buscar atalhos ou aprovação humana. Dá-me a coragem de ser o mesmo em público ou em segredo, confiando que a Tua proteção é maior do que qualquer pressão que este mundo possa impor. Amém.', 1),
('0b1cc802-a07b-4c1f-b774-8e2e8ea4473e', 'Pai', 'Papai do Céu, obrigado por me dar este filho precioso que alegra meus dias. Ajuda-me a cuidar dele com o Teu amor e paciência.', 1),
('0b1cc802-a07b-4c1f-b774-8e2e8ea4473e', 'Filho', 'Querido Deus, ajuda-me a obedecer com alegria ao papai e à mamãe hoje. Ensina-me a ser um filho amoroso e atencioso com eles.', 2),
('0b1cc802-a07b-4c1f-b774-8e2e8ea4473e', 'Juntos', 'Senhor, faz da nossa casa um lugar de união e obediência. Que o Teu amor nos guarde e nos guie em cada passo que dermos.', 3),
('0b65c0e8-e56d-4d91-8d0e-e03a76dffc7a', 'Individual', 'Senhor, reconheço que tudo o que tenho vem das Tuas mãos. Ajuda-me a manter o meu coração firme em Ti, para que, na abundância ou na perda, eu permaneça fiel e íntegro. Que a Tua soberania seja o meu porto seguro hoje e sempre. Amém.', 1),
('0b65d496-d89e-4c3c-a8c9-f3a735383407', 'Pai', 'Senhor, ajuda-me a guiar meus filhos com o exemplo e a ensinar-lhes que a Tua Palavra é o nosso guia seguro. Que possamos ser uma família que não se curva diante do medo.', 1),
('0b65d496-d89e-4c3c-a8c9-f3a735383407', 'Filho', 'Deus, dá-me coragem para escolher o que é certo, mesmo quando me sinto sozinho. Que eu seja forte para seguir os Teus mandamentos em todos os meus caminhos.', 2),
('0b65d496-d89e-4c3c-a8c9-f3a735383407', 'Juntos', 'Pai, confiamos que a Tua presença nos acompanha em cada desafio. Ajuda-nos a sermos fiéis e fortes, hoje e sempre, em nome de Jesus.', 3),
('0b9603a3-e1b7-4b2f-b541-98497c9d2bc6', 'Individual', 'Senhor, ajuda-me a manter um coração íntegro diante de todos, independentemente de como me tratam. Que meu respeito pelo próximo seja um reflexo direto do meu temor por Ti. Domina minha língua e meus pensamentos, para que, mesmo em meio às divergências, eu não perca a dignidade de quem vive para Te honrar em tudo. Amém.', 1),
('0ba0dedf-6e65-4339-8be6-1dd03e6c201f', 'Pai', 'Senhor, ajuda-nos a cultivar um lar onde a verdade é mais importante do que a aparência. Que nossos filhos tenham a coragem de Jônatas em sua caminhada.', 1),
('0ba0dedf-6e65-4339-8be6-1dd03e6c201f', 'Filho', 'Deus, dá-me forças para ser leal aos meus amigos e a minha família. Que eu não me esconda atrás de medos ao tomar decisões difíceis.', 2),
('0ba0dedf-6e65-4339-8be6-1dd03e6c201f', 'Juntos', 'Pai, que nossa união seja selada pela Tua verdade. Ensina-nos a escolher a lealdade em cada escolha que fizermos hoje.', 3),
('0bc465ff-2fd6-45d8-aecd-6357bdce46fc', 'Pai', 'Senhor, dá-nos a coragem de Daniel para sermos fiéis aos Teus ensinamentos em qualquer lugar. Ajuda-me a guiar meus filhos no caminho da retidão.', 1),
('0bc465ff-2fd6-45d8-aecd-6357bdce46fc', 'Filho', 'Pai do Céu, dá-me autocontrole para dizer não ao que é errado, mesmo quando todos os meus amigos dizem sim.', 2),
('0bc465ff-2fd6-45d8-aecd-6357bdce46fc', 'Juntos', 'Que a nossa casa seja um lugar de fidelidade a Ti. Que nossas escolhas diárias honrem sempre o Teu nome.', 3),
('0c5f3aa1-9891-4a86-9836-901adf7c03b4', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos a valorizarem a verdade acima da popularidade. Que sejamos modelos de coragem e temor ao Senhor dentro de nossa casa.', 1),
('0c5f3aa1-9891-4a86-9836-901adf7c03b4', 'Filho', 'Deus, dá-me forças para ser fiel a Ti mesmo quando meus amigos seguirem um caminho diferente. Que o meu caráter seja firme em todos os momentos.', 2),
('0c5f3aa1-9891-4a86-9836-901adf7c03b4', 'Juntos', 'Pai, ajuda-nos a manter nosso foco em Teus caminhos e a não ceder às pressões deste mundo. Que nossa família viva sempre para Te honrar.', 3),
('0d0f7fe3-125e-4b81-8e1f-aebd376c3ec6', 'Pai', 'Senhor, ajuda-nos a entender que o equilíbrio é um presente da Tua sabedoria. Ensina-nos a cultivar relacionamentos saudáveis e respeitosos.', 1),
('0d0f7fe3-125e-4b81-8e1f-aebd376c3ec6', 'Filho', 'Deus, dá-me o autocontrole necessário para saber a hora de calar e a hora de recuar. Que minhas palavras e presenças sejam sempre leves.', 2),
('0d0f7fe3-125e-4b81-8e1f-aebd376c3ec6', 'Juntos', 'Que a nossa família aprenda a viver com moderação, valorizando o espaço do próximo. Amém.', 3),
('0e7110cb-14ed-42b0-8d79-1c8b6352653a', 'Pai', 'Senhor, dá a nós a graça de sermos pais que acolhem com bondade e filhos que retornam com sinceridade. Ajuda-nos a manter nossa casa como um lugar de verdade.', 1),
('0e7110cb-14ed-42b0-8d79-1c8b6352653a', 'Filho', 'Pai do Céu, ajuda-me a não fugir das minhas responsabilidades. Que eu tenha coragem para admitir quando erro e buscar sempre o caminho da correção.', 2),
('0e7110cb-14ed-42b0-8d79-1c8b6352653a', 'Juntos', 'Que a reconciliação e o perdão sejam a base das nossas vidas. Caminharemos juntos, com humildade e olhos fixos em Teu amor.', 3),
('0e7aaae2-5a45-478b-bc88-a7d8ab910a51', 'Pai', 'Senhor, ajuda-nos a manter nosso lar como um lugar de perdão e acolhimento. Que possamos sempre correr ao encontro de nossos filhos com amor.', 1),
('0e7aaae2-5a45-478b-bc88-a7d8ab910a51', 'Filho', 'Pai, perdoa-me pelas vezes em que escolhi o caminho errado. Dá-me a coragem de ser sincero em minhas atitudes e decisões.', 2),
('0e7aaae2-5a45-478b-bc88-a7d8ab910a51', 'Juntos', 'Agradecemos pelo Teu amor que restaura e nos dá um novo recomeço. Ajuda-nos a caminhar sempre em Tua verdade.', 3),
('0eca71dd-f73e-4a14-b390-1aa85f947a7b', 'Pai', 'Senhor, dá a força necessária para que meus filhos permaneçam fiéis aos Teus mandamentos. Que a Tua verdade seja o centro de nossa casa.', 1),
('0eca71dd-f73e-4a14-b390-1aa85f947a7b', 'Filho', 'Deus, ajuda-me a ser corajoso como foram esses três jovens. Quero Te obedecer mesmo quando for difícil ou solitário.', 2),
('0eca71dd-f73e-4a14-b390-1aa85f947a7b', 'Juntos', 'Pai, ajuda-nos a escolher a Tua vontade acima da opinião de todos. Que a nossa vida glorifique o Teu nome todos os dias.', 3),
('0ecf614c-d0ad-4ade-82ac-7cdc6881035d', 'Pai', 'Senhor, ajuda-nos a confiar na Tua presença e na Tua Palavra. Que sejamos corajosos como Josué para enfrentar os desafios de cada dia.', 1),
('0ecf614c-d0ad-4ade-82ac-7cdc6881035d', 'Filho', 'Deus, dá-me coragem para fazer o que é certo na escola e com meus amigos. Ajuda-me a não ter medo de seguir a Tua vontade.', 2),
('0ecf614c-d0ad-4ade-82ac-7cdc6881035d', 'Juntos', 'Que a Tua força habite em nossa casa e guie nossas escolhas. Caminharemos confiantes, pois o Senhor está conosco por onde formos.', 3),
('0ef77545-4556-4c1d-9a42-88528254edf1', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos que a verdadeira força vem da Tua direção. Que possamos ser um porto seguro para eles quando o medo surgir.', 1),
('0ef77545-4556-4c1d-9a42-88528254edf1', 'Filho', 'Deus, eu quero confiar em Ti mesmo quando as coisas parecem difíceis na escola. Dá-me a Tua sabedoria para tomar decisões certas todos os dias.', 2),
('0ef77545-4556-4c1d-9a42-88528254edf1', 'Juntos', 'Pai, nós decidimos hoje colocar todas as nossas ansiedades em Tuas mãos. Que a Tua paz guie os nossos passos agora e sempre.', 3),
('0fcd6630-3ecd-4e43-88a8-748bb7138079', 'Pai', 'Senhor, dá a este meu filho a mesma coragem e sabedoria que deste a Daniel. Que ele permaneça fiel aos Teus mandamentos, independentemente das pressões que sofrer.', 1),
('0fcd6630-3ecd-4e43-88a8-748bb7138079', 'Filho', 'Deus, ajuda-me a escolher o que é certo mesmo quando ninguém estiver vendo. Que minha vida demonstre que Tu és o meu verdadeiro guia.', 2),
('0fcd6630-3ecd-4e43-88a8-748bb7138079', 'Juntos', 'Pai, fortalece nossa família para honrarmos Teu nome em cada decisão. Queremos Te obedecer acima de qualquer opinião humana.', 3),
('111d35f2-81ee-466d-a429-1a79f6ec95b9', 'Pai', 'Pai, ajuda-nos a ensinar nossos filhos a serem fiéis aos Teus mandamentos. Dá-nos coragem para sempre escolher o que é bom.', 1),
('111d35f2-81ee-466d-a429-1a79f6ec95b9', 'Filho', 'Querido Deus, ajuda-me a ser corajoso como Daniel. Quero sempre fazer o que Te deixa feliz.', 2),
('111d35f2-81ee-466d-a429-1a79f6ec95b9', 'Juntos', 'Senhor, obrigado por estares conosco em todos os lugares. Que a Tua verdade seja sempre o nosso foco.', 3),
('1166865c-1b65-4e74-ba03-b5ed6d78100d', 'Pai', 'Papai do Céu, obrigado por cada lição que aprendemos na Tua criação. Ensina-nos a confiar no Teu tempo perfeito.', 1),
('1166865c-1b65-4e74-ba03-b5ed6d78100d', 'Filho', 'Jesus, ajuda meu coração a ser paciente enquanto espero. Quero ser forte como uma borboleta.', 2),
('1166865c-1b65-4e74-ba03-b5ed6d78100d', 'Juntos', 'Queremos aprender a esperar com amor e alegria. Que o Senhor nos guie em todos os nossos dias.', 3),
('117bf8ef-b492-4367-84d2-f9128e3794a7', 'Individual', 'Senhor, dá-me a coragem dos três jovens para manter minha integridade mesmo quando o mundo exige conformidade. Que a minha lealdade a Ti seja maior que o medo da rejeição ou das perdas, e que meu caráter seja forjado na verdade, independentemente de qualquer plateia. Amém.', 1),
('119e217f-b887-4ef4-b589-25b8fb69e15d', 'Pai', 'Senhor, ajuda-nos a valorizar a obediência sincera em casa e na vida. Que nossa família seja marcada pela verdade que vem do alto.', 1),
('119e217f-b887-4ef4-b589-25b8fb69e15d', 'Filho', 'Deus, dá-me coragem para fazer o que é certo, mesmo quando ninguém estiver me vendo. Quero ter um coração íntegro como o de Davi.', 2),
('119e217f-b887-4ef4-b589-25b8fb69e15d', 'Juntos', 'Pai, guia nossos passos no caminho da justiça todos os dias. Que a nossa vida seja um reflexo da Tua verdade sempre.', 3),
('11afff0b-dd85-4f0f-95af-7fba30466352', 'Individual', 'Senhor, dá-me a mesma constância de Daniel para te servir sem medo. Que a minha integridade seja inabalável, independentemente das pressões que me cercam, mantendo-me fiel a Ti em cada decisão do meu dia.', 1),
('11d0f394-a3c0-4a21-aee5-338211247e7a', 'Pai', 'Senhor, dá aos nossos filhos a sabedoria para reconhecerem quando estão no caminho errado. Que eles encontrem em nossa casa um porto seguro para a verdade.', 1),
('11d0f394-a3c0-4a21-aee5-338211247e7a', 'Filho', 'Pai do céu, ajuda-me a ser honesto sobre minhas falhas e a escolher amigos que me incentivem a caminhar em retidão.', 2),
('11d0f394-a3c0-4a21-aee5-338211247e7a', 'Juntos', 'Obrigado, Deus, pelo teu amor que nos espera e nos acolhe. Ensina-nos a viver sempre na verdade.', 3),
('1252fd7f-85d1-4800-a269-61cbb36d55c7', 'Pai', 'Senhor, ajuda-nos a valorizar Tua Palavra mais do que qualquer ganho passageiro. Dá-nos coragem para ensinar nossos filhos a escolherem o que é certo.', 1),
('1252fd7f-85d1-4800-a269-61cbb36d55c7', 'Filho', 'Deus, ajuda-me a ser firme nas minhas decisões quando for difícil seguir o Teu caminho. Que meus olhos estejam fixos em Ti em todos os momentos.', 2),
('1252fd7f-85d1-4800-a269-61cbb36d55c7', 'Juntos', 'Pai, caminharemos unidos, buscando sempre a Tua vontade em nossas escolhas diárias. Que a nossa vida glorifique o Teu nome em tudo o que fizermos.', 3),
('127d7f38-f884-4e18-b1e1-73d9b8d19f2a', 'Individual', 'Senhor, ajuda-me a enxergar meus caminhos com a mesma clareza com que o filho pródigo viu o seu. Livra-me do orgulho que me impede de reconhecer meus erros e concede-me coragem para abandonar qualquer postura de autodefesa. Que o meu coração esteja sempre inclinado à verdade e que eu não tema a responsabilidade que acompanha o desejo de retornar ao teu caminho. Amém.', 1),
('12a2c586-bef2-4b53-99be-d61f65bde51c', 'Pai', 'Senhor, ensina-nos a valorizar a fidelidade acima de qualquer vantagem pessoal. Que nossa casa seja um lugar de honra e compromisso.', 1),
('12a2c586-bef2-4b53-99be-d61f65bde51c', 'Filho', 'Deus, ajuda-me a ser leal aos meus valores, mesmo quando for difícil escolher o certo. Que eu honre a Ti em cada decisão.', 2),
('12a2c586-bef2-4b53-99be-d61f65bde51c', 'Juntos', 'Pai, fortalece nossos laços de lealdade um com o outro e contigo. Que nossas escolhas sejam sempre um testemunho da Tua verdade.', 3),
('12e5e3da-b3e2-4ba0-a32b-39dc5941353b', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos a valorizarem a prudência. Que eles aprendam a ouvir a Tua voz acima da pressa.', 1),
('12e5e3da-b3e2-4ba0-a32b-39dc5941353b', 'Filho', 'Papai do Céu, me ajuda a pensar antes de agir. Quero ser atento e cuidadoso em todos os meus passos hoje.', 2),
('12e5e3da-b3e2-4ba0-a32b-39dc5941353b', 'Juntos', 'Que a Tua sabedoria nos guie em nossa casa. Obrigado por nos proteger e nos ensinar o caminho da paz.', 3),
('12fc80ba-6a04-415f-96e9-271684ebed15', 'Individual', 'Senhor, examina o meu coração e revela se tenho permitido que vozes alheias à Tua vontade ditem meus passos. Dá-me sabedoria para cultivar amizades que fortalecem minha integridade e coragem para me afastar de influências que silenciam a Tua voz em mim. Que eu seja fiel a Ti todos os dias. Amém.', 1),
('13a4cedb-e08c-4ebc-9116-bda9cdb2c7d6', 'Individual', 'Senhor, ajuda-me a manter os olhos firmes na obra que me deste. Que o ruído ao meu redor não seja mais alto que a Tua voz, e que minhas mãos permaneçam diligentes e fiéis, independentemente das críticas. Ensina-me a governar meu foco e a buscar Tua proteção para o que construo. Amém.', 1),
('13f0683c-57bd-404d-adbb-e395e8bb1172', 'Pai', 'Senhor, ajuda-nos a ver as dificuldades como oportunidades para crescer. Ensina-nos a confiar em Teu tempo e a não ceder à impaciência.', 1),
('13f0683c-57bd-404d-adbb-e395e8bb1172', 'Filho', 'Deus, dá-me autocontrole quando eu estiver sob pressão. Que eu saiba agir com sabedoria em vez de apenas reagir por impulso.', 2),
('13f0683c-57bd-404d-adbb-e395e8bb1172', 'Juntos', 'Pedimos um coração constante que não desiste do que é certo. Que nossa família seja firme em Ti, em todos os momentos.', 3),
('142575f8-b102-43f9-8248-4ece598b56fa', 'Pai', 'Senhor, ensina-nos a enxergar as pessoas como o Senhor enxerga. Não nos deixe passar indiferentes diante de quem precisa de auxílio.', 1),
('142575f8-b102-43f9-8248-4ece598b56fa', 'Filho', 'Deus, ajuda-me a não ter medo de fazer o certo, mesmo que seja difícil. Dá-me coragem para estender a mão a quem está sozinho.', 2),
('142575f8-b102-43f9-8248-4ece598b56fa', 'Juntos', 'Pai, que nossas vidas sejam marcadas por ações concretas de amor. Que o Teu cuidado flua através de nós para todos ao nosso redor.', 3),
('14293988-f35a-4e86-8df2-0b1189e1f1e1', 'Pai', 'Pai, ajuda-me a ser um exemplo de perdão e acolhimento para o meu filho. Que ele encontre em mim segurança para sempre confessar seus erros.', 1),
('14293988-f35a-4e86-8df2-0b1189e1f1e1', 'Filho', 'Pai do céu, perdoa as minhas faltas e o meu orgulho. Dá-me coragem para assumir meus erros e buscar a reconciliação.', 2),
('14293988-f35a-4e86-8df2-0b1189e1f1e1', 'Juntos', 'Senhor, que a nossa casa seja um lugar de verdade e recomeços. Obrigado porque Teu amor sempre nos convida a voltar para Ti.', 3),
('147c141a-4ae6-4b86-b8bf-38f817fab932', 'Pai', 'Senhor, ajuda-nos a criar filhos que buscam primeiro a Tua aprovação. Que nossa casa seja um lugar de oração constante.', 1),
('147c141a-4ae6-4b86-b8bf-38f817fab932', 'Filho', 'Deus, dá-me coragem para escolher o que é certo, mesmo quando meus amigos estiverem olhando ou me pressionando.', 2),
('147c141a-4ae6-4b86-b8bf-38f817fab932', 'Juntos', 'Que a nossa obediência a Ti seja firme todos os dias. Que a Tua verdade seja o nosso guia.', 3),
('148267b7-5526-4427-9205-effdc570f9d0', 'Individual', 'Senhor, que a minha decisão de Te servir não seja apenas um sentimento momentâneo, mas o firme alicerce de todas as minhas ações diárias. Dá-me a clareza de Josué para renunciar a tudo o que compete com a Tua vontade e a força necessária para manter minha integridade, mesmo quando ninguém além de Ti estiver observando. Que minha vida reflita o compromisso de quem caminha sob a Tua autoridade. Amém.', 1),
('152cafde-a612-4e98-ad35-8845b2b88f66', 'Individual', 'Senhor, concede-me a prudência necessária para edificar minha vida e meus relacionamentos sobre os fundamentos da Tua verdade. Que minhas palavras e escolhas de hoje sirvam para fortalecer o que é reto, e não para derrubar o que me deste. Amém.', 1),
('1532fe82-8651-4c7a-8521-9472af5910d6', 'Pai', 'Papai do Céu, ensina nossos filhos a serem amigos fiéis e bondosos. Que eles aprendam a cuidar daqueles que amamos com um coração puro.', 1),
('1532fe82-8651-4c7a-8521-9472af5910d6', 'Filho', 'Jesus, ajuda-me a ser como Rute e não abandonar quem precisa de mim. Quero ter um coração que sabe ficar junto nos momentos difíceis.', 2),
('1532fe82-8651-4c7a-8521-9472af5910d6', 'Juntos', 'Obrigado por nos unires em amor. Que nossa família seja um exemplo de lealdade e cuidado para todos ao nosso redor.', 3),
('15931dfa-13ff-4c47-9157-ff57ccf59773', 'Pai', 'Senhor, ajuda-nos a ter olhos que enxergam a dor alheia. Que não sejamos indiferentes ao sofrimento do nosso próximo.', 1),
('15931dfa-13ff-4c47-9157-ff57ccf59773', 'Filho', 'Pai, dá-me coragem para parar o meu dia e ajudar alguém. Que minhas ações sejam sinceras e não por busca de elogios.', 2),
('15931dfa-13ff-4c47-9157-ff57ccf59773', 'Juntos', 'Deus, transforma nossos corações para que a Tua compaixão guie nossas escolhas. Ensina-nos a servir como o samaritano serviu.', 3),
('15b24a43-8ab8-4ce0-a240-0e8f3b720abd', 'Individual', 'Senhor, concede-me a clareza para distinguir o que é urgente do que é eterno. Que a Tua sabedoria governe meus pensamentos e minhas ações, para que, em cada escolha, eu possa edificar um caminho de integridade. Livra-me da impulsividade e firma meus passos no Teu bom conselho. Amém.', 1),
('163a3b24-72ef-4d46-8ff5-4b576b70ba9b', 'Individual', 'Senhor, ajuda-me a manter a firmeza de Josué diante das escolhas que o mundo me impõe. Que a minha vida seja um reflexo coerente da minha fé, e que o meu agir diário comprove a quem eu decidi servir. Purifica o meu coração de qualquer divisão e firma os meus passos na tua verdade, para que o meu legado honre o teu nome acima de todas as coisas.', 1),
('16a9ef82-6c52-42d7-9355-793659af2ba4', 'Individual', 'Senhor, ajuda-me a manter a integridade quando for tentado a revidar o mal com o mal. Que o meu respeito pelas pessoas não dependa do comportamento delas, mas do meu compromisso contigo. Dá-me autogoverno para honrar, mesmo quando o ambiente for de conflito, para que o meu caráter reflita Tua justiça em todas as minhas decisões.', 1),
('170e5dd1-55d6-419a-b4fd-6e407acc7bcc', 'Pai', 'Senhor, ajuda-nos a depositar as ansiedades que carregamos diante da Tua soberania. Que a Tua paz guarde a mente de nossos filhos em cada escolha difícil.', 1),
('170e5dd1-55d6-419a-b4fd-6e407acc7bcc', 'Filho', 'Deus, tira do meu coração o medo do que virá amanhã. Ensina-me a confiar em Ti hoje, mesmo quando eu não puder ver o caminho.', 2),
('170e5dd1-55d6-419a-b4fd-6e407acc7bcc', 'Juntos', 'Que a Tua paz, que ultrapassa todo entendimento, seja a nossa proteção constante. Confiamos o nosso futuro inteiramente em Tuas mãos, amém.', 3),
('17166f34-8d1d-4484-bb0c-75d44bd5dffa', 'Pai', 'Senhor, dá-nos a coragem de ser fiéis ao Senhor, mesmo quando a pressão ao nosso redor for grande. Ajuda-nos a priorizar a Tua vontade acima da opinião dos outros.', 1),
('17166f34-8d1d-4484-bb0c-75d44bd5dffa', 'Filho', 'Deus, me ajude a não ter medo de fazer o que é certo na escola. Dá-me forças para ser corajoso e defender os Teus valores todos os dias.', 2),
('17166f34-8d1d-4484-bb0c-75d44bd5dffa', 'Juntos', 'Pai, que a nossa casa seja um lugar de firmeza e verdade. Que possamos sempre escolher o Teu caminho, aconteça o que acontecer.', 3),
('1768fbff-b539-46a9-99fe-f3938d68284b', 'Pai', 'Senhor, ensina meu filho a valorizar as pequenas tarefas de cada dia. Que ele cresça com um coração fiel e dedicado em tudo.', 1),
('1768fbff-b539-46a9-99fe-f3938d68284b', 'Filho', 'Papai do céu, me ajude a cuidar bem das minhas coisas e a ser obediente. Quero ser alguém em quem o Senhor pode confiar.', 2),
('1768fbff-b539-46a9-99fe-f3938d68284b', 'Juntos', 'Obrigado, Deus, porque o Senhor nos ama e nos ensina o caminho certo. Que nossa casa seja um lugar de fidelidade!', 3),
('1769a068-8e5c-4ecb-90fd-b006c83b8983', 'Pai', 'Senhor, ajuda-nos a sermos pais que acolhem com o coração aberto. Que possamos sempre demonstrar o Teu perdão aos nossos filhos.', 1),
('1769a068-8e5c-4ecb-90fd-b006c83b8983', 'Filho', 'Pai do Céu, dá-me coragem para admitir quando erro. Que eu não tenha medo de buscar o perdão e recomeçar.', 2),
('1769a068-8e5c-4ecb-90fd-b006c83b8983', 'Juntos', 'Obrigado pela Tua graça que nos alcança onde quer que estejamos. Ensina-nos a viver sempre na verdade e na compaixão.', 3),
('177dc729-777c-4a87-b6d7-3664489ad284', 'Pai', 'Senhor, obrigado pelo mel e por todas as doçuras que o Senhor criou para nós. Ensina-nos a agradecer por cada presente sem pedir mais do que precisamos.', 1),
('177dc729-777c-4a87-b6d7-3664489ad284', 'Filho', 'Papai do Céu, ajuda-me a ser uma criança que sabe a hora de parar de brincar ou de comer. Quero ser sábio como o rei Salomão e cuidar bem das coisas.', 2),
('177dc729-777c-4a87-b6d7-3664489ad284', 'Juntos', 'Obrigado, Deus, pela tua medida perfeita em tudo. Ajuda nossa família a viver sempre com alegria e moderação.', 3),
('18041a9a-396d-48cb-9d6a-c4317486f9fd', 'Pai', 'Pai do Céu, peço que ajudes meu filho a encontrar amigos que amem a Tua Palavra. Que ele aprenda a seguir o exemplo daqueles que buscam a sabedoria.', 1),
('18041a9a-396d-48cb-9d6a-c4317486f9fd', 'Filho', 'Querido Deus, ajuda-me a escolher amigos que sejam gentis e bons. Quero aprender coisas certas com eles todos os dias.', 2),
('18041a9a-396d-48cb-9d6a-c4317486f9fd', 'Juntos', 'Senhor, torna nossa casa e nossas amizades um lugar de luz. Caminharemos juntos no Teu bom caminho, hoje e sempre.', 3),
('1809a0db-cdc2-45ac-81ca-f7f8889b8f4d', 'Individual', 'Senhor, reconheço que muitas vezes falhei ao não medir o peso das minhas palavras. Peço que a Tua sabedoria governe meus lábios, para que eu não lance sementes de morte sobre aqueles que amo. Capacita-me a ser alguém cujo falar seja reflexo do Teu caráter, escolhendo sempre a vida e a verdade em cada conversa. Amém.', 1),
('1864cd35-0bba-4065-84bb-3b3e9de999c3', 'Pai', 'Senhor, ajuda-me a educar meus filhos com firmeza, para que eles amem a Tua Palavra acima das facilidades deste mundo. Que sejamos um lar que prioriza o que é eterno.', 1),
('1864cd35-0bba-4065-84bb-3b3e9de999c3', 'Filho', 'Pai Celestial, dá-me coragem para permanecer fiel aos Teus mandamentos, mesmo quando for mais fácil seguir a maioria. Que minha vida demonstre Tua sabedoria em tudo.', 2),
('1864cd35-0bba-4065-84bb-3b3e9de999c3', 'Juntos', 'Deus, ajuda-nos a ser fiéis em nossas escolhas diárias. Que a nossa obediência a Ti seja a nossa maior força contra as tempestades da vida.', 3),
('18926b9a-06b6-486e-b661-37696dbe3b96', 'Pai', 'Senhor, ajuda-nos a entender que as dificuldades não são apenas problemas, mas oportunidades para crescer. Dá-nos sabedoria para ensinar aos nossos filhos a esperarem em Ti.', 1),
('18926b9a-06b6-486e-b661-37696dbe3b96', 'Filho', 'Deus, ajuda-me a não agir sem pensar quando estiver sob pressão. Dá-me força para ser íntegro, mesmo quando for difícil seguir o que é certo.', 2),
('18926b9a-06b6-486e-b661-37696dbe3b96', 'Juntos', 'Pai, que a nossa casa seja um lugar de paciência e maturidade. Que nossa resistência ao erro brilhe como um exemplo do Teu amor em nós.', 3),
('18eaf8e6-c804-4192-9a8a-d755d825953c', 'Pai', 'Senhor, dá ao meu filho a sabedoria e a força de Daniel para ser fiel. Que ele encontre em Ti a segurança que o mundo não pode oferecer.', 1),
('18eaf8e6-c804-4192-9a8a-d755d825953c', 'Filho', 'Deus, ajuda-me a não ter medo do que vão pensar de mim na escola. Dá-me coragem para escolher o que é certo, mesmo quando estiver sozinho.', 2),
('18eaf8e6-c804-4192-9a8a-d755d825953c', 'Juntos', 'Pai, que nossa família sempre escolha obedecer à Tua vontade acima da opinião dos outros. Que nossa vida seja um testemunho de integridade.', 3),
('195636a2-6825-403c-9508-e4c84a7074fb', 'Pai', 'Pai, obrigado por seres a nossa Rocha segura. Ensina-nos a Te louvar com alegria todos os dias.', 1),
('195636a2-6825-403c-9508-e4c84a7074fb', 'Filho', 'Papai do Céu, obrigado por cuidares de mim como um pastor cuida da ovelha. Eu quero Te cantar louvores!', 2),
('195636a2-6825-403c-9508-e4c84a7074fb', 'Juntos', 'Senhor, nossa casa é Tua casa. Que a alegria do Teu amor esteja sempre em nossos corações.', 3),
('197b59ba-583c-4ce7-a4a7-31d7ef703c5f', 'Pai', 'Senhor, ajuda-me a guiar meu filho para enxergar além das aparências. Que sejamos sábios em nossas escolhas diárias.', 1),
('197b59ba-583c-4ce7-a4a7-31d7ef703c5f', 'Filho', 'Deus, dá-me olhos que buscam primeiro o que é justo e verdadeiro. Ajuda-me a fugir do que parece bom, mas me afasta de Ti.', 2),
('197b59ba-583c-4ce7-a4a7-31d7ef703c5f', 'Juntos', 'Pai, abençoa nossa família para permanecermos firmes em Tua vontade. Que nossos caminhos sempre conduzam à Tua presença.', 3),
('197dc869-1cdb-4a41-8ab4-8bcd8b893eed', 'Individual', 'Senhor, reconheço que muitas vezes minha generosidade é limitada pelo medo e pela busca de segurança própria. Ensina-me a confiar que Tu és o meu sustento, para que minha vida seja marcada pela entrega sincera e não apenas pelo que me sobra. Que o meu coração esteja livre da avareza e inteiramente disposto a servir conforme a Tua vontade. Amém.', 1),
('19a6fddd-cee6-4b51-bd64-b729c348db3d', 'Pai', 'Senhor, ajude meu filho a valorizar a obediência acima da facilidade. Que ele encontre em Ti a força para ser um jovem de caráter reto.', 1),
('19a6fddd-cee6-4b51-bd64-b729c348db3d', 'Filho', 'Deus, dá-me sabedoria para escolher o que é certo mesmo quando ninguém estiver me vendo. Quero crescer em sabedoria e graça diante de Ti.', 2),
('19a6fddd-cee6-4b51-bd64-b729c348db3d', 'Juntos', 'Pai, abençoe nossa família com um coração obediente. Que nossa casa seja um lugar onde a integridade sempre vença a vontade própria.', 3),
('19f945e1-c4b6-42ca-a0bf-956b2ef632be', 'Pai', 'Senhor, ajuda-nos a olhar para as pessoas com o mesmo amor que Jesus olhava. Que nossa casa seja um lugar de serviço e bondade.', 1),
('19f945e1-c4b6-42ca-a0bf-956b2ef632be', 'Filho', 'Papai do Céu, ensina-me a ser humilde e a dividir minhas coisas com alegria. Quero ser um bom amigo como Jesus me ensinou.', 2),
('19f945e1-c4b6-42ca-a0bf-956b2ef632be', 'Juntos', 'Obrigado, Deus, pelo Teu exemplo. Ajuda-nos a amar e servir uns aos outros todos os dias!', 3),
('1a2558d4-210d-4623-a430-2d330e4b23ab', 'Individual', 'Senhor, reconheço que recebi de Ti uma misericórdia que nunca poderia pagar. Ajuda-me a governar o meu coração para que eu não me torne um cobrador implacável das falhas alheias. Remove da minha mente todo registro de vingança e concede-me a integridade necessária para perdoar como fui perdoado. Amém.', 1),
('1a4f6424-ab10-401a-9a12-d15cbf211f24', 'Pai', 'Senhor, dá-me a coragem de ser um exemplo de verdade em casa. Ajuda-me a guiar meu filho com integridade e sabedoria.', 1),
('1a4f6424-ab10-401a-9a12-d15cbf211f24', 'Filho', 'Deus, ajuda-me a falar a verdade sempre, mesmo quando for difícil ou eu tiver medo. Que minhas palavras sejam sempre firmes e corretas.', 2),
('1a4f6424-ab10-401a-9a12-d15cbf211f24', 'Juntos', 'Pai, faz da nossa família um lugar onde a verdade é o nosso maior tesouro. Que honremos o Teu nome através da honestidade.', 3),
('1aacac06-9b69-4832-86a0-71a38ded3f3e', 'Individual', 'Senhor, ajuda-me a edificar uma fé que não dependa do conforto para permanecer fiel. Que a Tua verdade seja a bússola do meu autogoverno e que, diante de qualquer pressão, eu prefira a Tua aprovação à conveniência do mundo. Fortalece minha integridade para que eu permaneça inabalável em cada escolha do dia a dia. Amém.', 1),
('1ada0bd6-51e1-4f64-b616-26e0145ebcce', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos que a Tua vontade é o nosso melhor caminho. Dá-nos sabedoria para sermos exemplos de firmeza e amor.', 1),
('1ada0bd6-51e1-4f64-b616-26e0145ebcce', 'Filho', 'Papai do Céu, ajuda meu coração a ser corajoso como o de Daniel. Quero sempre escolher o que é certo, mesmo quando ninguém estiver olhando.', 2),
('1ada0bd6-51e1-4f64-b616-26e0145ebcce', 'Juntos', 'Obrigado, Deus, por estares sempre conosco. Ajuda nossa família a crescer forte e unida em Tua verdade todos os dias!', 3),
('1b5fc897-53dd-4e21-bf7c-de7d9ea3b6bd', 'Individual', 'Senhor, perdoa-me por tentar carregar o peso do mundo com minhas forças limitadas. Reconheço meu cansaço e minha tendência a ignorar a Tua voz em meio às minhas preocupações. Que o Teu silêncio me ensine a esperar, e que a Tua voz mansa restaure a minha coragem para seguir fielmente o Teu caminho. Amém.', 1),
('1b65baef-cee4-443c-9f4a-d3c3fc7674c9', 'Individual', 'Senhor, peço sabedoria para examinar a influência que meus relacionamentos exercem sobre minha alma. Que a Tua verdade seja o filtro das vozes que escuto, e que eu tenha coragem de cultivar amizades que me aproximem da Tua vontade. Guarda o meu coração contra o erro e firma os meus passos na integridade. Amém.', 1),
('1cf792f0-b515-4771-a7bc-4c2922a0639f', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos que a Tua aprovação vale mais do que o aplauso de qualquer grupo.', 1),
('1cf792f0-b515-4771-a7bc-4c2922a0639f', 'Filho', 'Deus, dá-me coragem para ser fiel às Tuas palavras na escola, mesmo quando ninguém mais estiver sendo.', 2),
('1cf792f0-b515-4771-a7bc-4c2922a0639f', 'Juntos', 'Pai, que nossa família sempre escolha o caminho da verdade, confiando que o Senhor nos guia e protege.', 3),
('1d29aec4-6c19-4036-b444-d384a6580894', 'Pai', 'Senhor, ajuda-nos a cultivar convicções que honram o Teu nome em nosso lar. Que sejamos um exemplo de fidelidade uns para os outros.', 1),
('1d29aec4-6c19-4036-b444-d384a6580894', 'Filho', 'Deus, dá-me coragem para dizer não quando o mundo oferecer algo que Te desagrada. Guarda o meu coração das escolhas que me afastam de Ti.', 2),
('1d29aec4-6c19-4036-b444-d384a6580894', 'Juntos', 'Pai, que a nossa casa seja um lugar de obediência e verdade. Que possamos sempre escolher o Teu caminho acima de qualquer pressão.', 3),
('1d997423-24c4-42b1-894e-949009f229bb', 'Individual', 'Senhor, ajuda-me a manter meu foco em Ti, independentemente das pressões que me cercam. Que o meu compromisso diário em oração seja mais forte do que o meu medo de enfrentar perdas ou rejeição. Concede-me a coragem de ser fiel ao Teu chamado, mesmo quando o ambiente ao meu redor exigir que eu negue a minha fé. Amém.', 1),
('1e42daf7-6fab-46e5-b1ce-74b407532500', 'Individual', 'Senhor, ajuda-me a edificar convicções inabaláveis em Ti. Que a Tua verdade seja mais real para mim do que qualquer ameaça ou pressão ao meu redor, dando-me coragem para manter minha integridade, ainda que eu tenha de caminhar sozinho.', 1),
('1e6fcf97-2828-4585-99a1-4a88eea29bd6', 'Pai', 'Senhor, ajuda-me a ser um exemplo de firmeza e retidão para meus filhos. Que possamos edificar nossa casa sobre o fundamento da Tua sabedoria.', 1),
('1e6fcf97-2828-4585-99a1-4a88eea29bd6', 'Filho', 'Deus, dá-me forças para controlar meus impulsos e escolher o que é certo. Ajuda-me a ser forte quando ninguém estiver olhando.', 2),
('1e6fcf97-2828-4585-99a1-4a88eea29bd6', 'Juntos', 'Pai, que nossas escolhas de hoje fortaleçam nossa caminhada contigo. Que sejamos muralhas firmes na verdade, agora e sempre.', 3),
('1ec6964d-e672-4f65-b002-58a0f510f9b7', 'Individual', 'Senhor, ajuda-me a discernir o valor dos meus relacionamentos sob a Tua luz. Que eu não me perca em amizades superficiais de conveniência, mas que tenha a coragem de ser um amigo leal, disposto a servir e sacrificar-me conforme o Teu exemplo. Ensina-me a ser alguém em quem os outros possam confiar e que honra os laços verdadeiros com integridade e fidelidade. Amém.', 1),
('1ed0861d-de79-44d4-8c66-5c450962a1b2', 'Pai', 'Senhor, ajuda-nos a ensinar nosso filho a Te amar e a Te respeitar acima de tudo. Que o nosso exemplo de obediência seja um reflexo do Teu cuidado.', 1),
('1ed0861d-de79-44d4-8c66-5c450962a1b2', 'Filho', 'Papai do céu, ajuda o meu coração a ser obediente e a aprender que Tu és o meu melhor guia. Quero ser sábio como a árvore que tem raízes firmes.', 2),
('1ed0861d-de79-44d4-8c66-5c450962a1b2', 'Juntos', 'Obrigado, Deus, por seres nosso Pai amoroso. Ensina-nos a caminhar sempre pertinho de Ti, todos os dias da nossa vida.', 3),
('1ed695c6-04ff-4f71-a196-05945acc3137', 'Pai', 'Senhor, dá a meu filho sabedoria para reconhecer seus erros e coragem para ser sempre verdadeiro. Que ele valorize a integridade acima de qualquer aprovação humana.', 1),
('1ed695c6-04ff-4f71-a196-05945acc3137', 'Filho', 'Pai do céu, ajuda-me a não fugir da verdade quando eu errar. Dá-me um coração humilde para pedir perdão e aprender com minhas falhas.', 2),
('1ed695c6-04ff-4f71-a196-05945acc3137', 'Juntos', 'Que nossa casa seja um lugar de verdade e perdão. Conduze nossos passos para que possamos sempre escolher o caminho que honra a Ti.', 3),
('1edb0ac2-e45b-43b0-82a4-67a5f47426e5', 'Pai', 'Senhor, ajuda-nos a buscar primeiro a Tua sabedoria, assim como Salomão fez. Que nosso lar seja um lugar de escolhas honradas.', 1),
('1edb0ac2-e45b-43b0-82a4-67a5f47426e5', 'Filho', 'Deus, dá-me um coração atento para distinguir o que é certo do que é errado. Ensina-me a ser prudente em cada passo.', 2),
('1edb0ac2-e45b-43b0-82a4-67a5f47426e5', 'Juntos', 'Que a Tua luz guie as nossas decisões diárias e nos prepare para o futuro. Amém.', 3),
('1f0c7f6c-ab4d-479b-8d98-daeb7003cddb', 'Individual', 'Senhor, perdoa-me pelas vezes em que preferi esconder meus erros sob o manto da justificativa. Concede-me a coragem de Natã para ouvir a Tua voz e a humildade de Davi para confessar, sem reservas, tudo o que tem corrompido meu coração. Que a Tua verdade seja o filtro de todas as minhas ações hoje. Amém.', 1),
('1fc08045-6675-415f-821c-8788f492f3be', 'Pai', 'Senhor, ajuda-nos a valorizar mais o caráter do que o reconhecimento das pessoas. Dá-nos sabedoria para sermos íntegros em cada pequena escolha.', 1),
('1fc08045-6675-415f-821c-8788f492f3be', 'Filho', 'Deus, ajuda-me a manter meu nome limpo diante de Ti e dos meus amigos. Dá-me coragem para escolher o que é certo hoje.', 2),
('1fc08045-6675-415f-821c-8788f492f3be', 'Juntos', 'Que o nosso nome reflita sempre a Tua verdade e a Tua bondade. Amém.', 3),
('1ffc2513-421d-45e0-88d2-a667d153c652', 'Individual', 'Senhor, reconheço que muitas vezes meu coração é solo fértil para o orgulho e a discórdia. Ensina-me a governar meu espírito para que eu não responda ao mal com a força, mas com a tua sabedoria. Capacita-me a ser um instrumento de reconciliação, capaz de trazer a luz da tua paz aos lugares de conflito em que transito diariamente. Amém.', 1),
('201dcac2-5cd1-4df2-b38d-30175768f1d0', 'Pai', 'Papai do Céu, ensina-nos a confiar nas Tuas palavras. Ajuda-nos a amar mais a Tua vontade do que as nossas vontades passageiras.', 1),
('201dcac2-5cd1-4df2-b38d-30175768f1d0', 'Filho', 'Jesus, ajuda meu coração a ser paciente. Quando eu quiser algo que não posso ter, ajuda-me a lembrar que o Senhor cuida de mim.', 2),
('201dcac2-5cd1-4df2-b38d-30175768f1d0', 'Juntos', 'Obrigado, Deus, pelo Teu amor que nos guia. Queremos crescer obedientes e felizes ao Teu lado, todos os dias.', 3),
('20234dbc-215f-4a63-af1d-522db127d802', 'Pai', 'Senhor, dá discernimento ao meu filho para escolher amigos que edifiquem sua fé. Que ele encontre pessoas que honrem a Ti acima de qualquer grupo.', 1),
('20234dbc-215f-4a63-af1d-522db127d802', 'Filho', 'Pai do céu, ajuda-me a ser forte e a não ceder à pressão dos meus colegas. Quero caminhar com pessoas que amam a Tua Palavra.', 2),
('20234dbc-215f-4a63-af1d-522db127d802', 'Juntos', 'Que nossas amizades sejam sempre um reflexo da Tua verdade e luz em nossas vidas. Amém!', 3),
('204d499e-114a-4213-bb2e-250879e741c2', 'Pai', 'Senhor, ajuda-nos a valorizar a integridade acima de qualquer ganho material. Que o nosso legado seja fundamentado na Tua justiça.', 1),
('204d499e-114a-4213-bb2e-250879e741c2', 'Filho', 'Pai celestial, dá-me forças para escolher o que é certo mesmo quando ninguém está olhando. Que a minha vida seja transparente diante de Ti.', 2),
('204d499e-114a-4213-bb2e-250879e741c2', 'Juntos', 'Que nossa família caminhe em verdade e que o nosso nome reflita sempre a Tua fidelidade. Amém.', 3),
('20958134-9248-41ad-8c69-4b95109f6c97', 'Pai', 'Senhor, ensina-nos a ter a prontidão do pai da parábola para acolher quem errou. Que nosso lar seja sempre um lugar de perdão e portas abertas.', 1),
('20958134-9248-41ad-8c69-4b95109f6c97', 'Filho', 'Deus, tira do meu coração o medo de buscar reconciliação. Dá-me forças para admitir meus erros e restaurar as amizades que estão distantes.', 2),
('20958134-9248-41ad-8c69-4b95109f6c97', 'Juntos', 'Agradecemos pelo Teu perdão infinito que nos alcança. Que a nossa família caminhe sempre na unidade e na paz do Teu amor.', 3),
('20a1e0ba-e861-4fae-ac19-a074992ce27b', 'Pai', 'Pai, ensina nossos filhos a terem um coração bondoso como o do samaritano. Ajuda-os a serem atentos às necessidades de quem está ao redor.', 1),
('20a1e0ba-e861-4fae-ac19-a074992ce27b', 'Filho', 'Jesus, ajuda-me a ver quem precisa de ajuda hoje. Quero ser um amigo carinhoso e fazer o bem para os outros.', 2),
('20a1e0ba-e861-4fae-ac19-a074992ce27b', 'Juntos', 'Senhor, faze-nos um instrumento de bondade. Que possamos amar e cuidar uns dos outros sempre!', 3),
('212f6ee6-5584-4ce5-99aa-8cc9249cb003', 'Individual', 'Senhor, perdoa-me pela tendência de exigir provas antes de obedecer. Concede-me a coragem de Abraão para agir conforme a Tua direção, confiando que a Tua fidelidade é a única garantia necessária para meus passos hoje. Amém.', 1),
('2163a3f1-8a75-45c1-86d6-4b3b45710cf5', 'Individual', 'Senhor, perdoa a minha pressa em querer colher o que ainda não foi plantado ou processado em mim. Ajuda-me a ser fiel nas pequenas responsabilidades e a confiar na Tua soberania durante os tempos de silêncio. Que o meu caráter seja fortalecido pela Tua palavra, mantendo a minha integridade acima de qualquer reconhecimento humano. Amém.', 1),
('219b0bfd-42cb-42fd-a592-a0c4ce7a22ae', 'Pai', 'Papai do céu, ajuda meu filho a escolher amigos que amam o Senhor. Que ele aprenda a caminhar com pessoas que trazem paz e sabedoria.', 1),
('219b0bfd-42cb-42fd-a592-a0c4ce7a22ae', 'Filho', 'Querido Deus, ajuda-me a ser um bom amigo para os outros. Que eu escolha companheiros que me ajudem a fazer o que é certo.', 2),
('219b0bfd-42cb-42fd-a592-a0c4ce7a22ae', 'Juntos', 'Obrigado, Deus, pela alegria da amizade verdadeira. Que nossos corações sejam sempre unidos pelo Teu amor e pela Tua luz.', 3),
('222a5cb9-fcfb-4730-8614-6667a4ff5ade', 'Pai', 'Papai do céu, ensina-nos a perdoar como Esaú perdoou. Ajuda nossa família a sempre escolher o abraço em vez da briga.', 1),
('222a5cb9-fcfb-4730-8614-6667a4ff5ade', 'Filho', 'Jesus, ajuda meu coração a não guardar raiva. Que eu saiba pedir desculpas e ser um amigo bondoso todos os dias.', 2),
('222a5cb9-fcfb-4730-8614-6667a4ff5ade', 'Juntos', 'Obrigado por nos unires em amor. Que a nossa casa seja sempre um lugar de paz e perdão, amém!', 3),
('2232ca16-2685-45ad-9f29-742cd2388a9e', 'Pai', 'Senhor, ajuda-nos a criar um lar onde a verdade seja sempre bem-vinda. Dá aos nossos filhos a coragem de nos procurar sempre que errarem.', 1),
('2232ca16-2685-45ad-9f29-742cd2388a9e', 'Filho', 'Pai do Céu, perdoa quando tento esconder meus erros por medo ou orgulho. Dá-me forças para ser honesto e buscar o caminho de volta.', 2),
('2232ca16-2685-45ad-9f29-742cd2388a9e', 'Juntos', 'Deus, ensina-nos a valorizar a verdade acima de nossa imagem. Que o nosso amor seja sempre maior do que qualquer falha cometida.', 3),
('22831bcf-95ee-44eb-873b-ddc12a3c3eec', 'Individual', 'Senhor, examina o meu coração e os meus vínculos. Reconheço que não sou autossuficiente e que a influência daqueles que me cercam molda os meus passos. Dá-me discernimento e coragem para zelar por quem permito compartilhar minha intimidade. Que meu coração não se incline a nada que Te desagrade, e que as minhas amizades sejam um reflexo da minha busca constante por Tua vontade. Amém.', 1),
('22f68fef-7505-41f1-87e5-aea2b36bdf6a', 'Pai', 'Senhor, ajuda-nos a entender que tudo o que temos vem da Tua mão bondosa. Ensina nossos filhos a serem generosos com o tempo e os talentos que recebem de Ti.', 1),
('22f68fef-7505-41f1-87e5-aea2b36bdf6a', 'Filho', 'Deus, tira do meu coração o desejo de guardar tudo só para mim. Dá-me coragem para compartilhar o que aprendo e ajudar meus amigos com um coração alegre.', 2),
('22f68fef-7505-41f1-87e5-aea2b36bdf6a', 'Juntos', 'Que a nossa casa seja um lugar de mãos abertas e coração farto. Que a Tua generosidade flua através de nós para todos ao nosso redor, amém.', 3),
('23749ec2-a4cf-474f-a6b6-1e49f3c57716', 'Pai', 'Senhor, ajuda-nos a confiar em Tua soberania mesmo nos dias difíceis. Ensina-nos a depositar em Tuas mãos cada inquietação que carregamos.', 1),
('23749ec2-a4cf-474f-a6b6-1e49f3c57716', 'Filho', 'Pai, eu te entrego a minha ansiedade sobre minhas responsabilidades e amigos. Peço que a Tua paz cuide dos meus pensamentos hoje.', 2),
('23749ec2-a4cf-474f-a6b6-1e49f3c57716', 'Juntos', 'Obrigado, Deus, porque o Senhor guarda o nosso coração com Tua paz. Confiamos que o Senhor está conosco em todo tempo.', 3),
('23b609c6-e094-4a41-af34-92e05deee08f', 'Individual', 'Senhor, perdoa-me pela pressa e pela falta de fé que me fazem silenciar diante das dificuldades. Ajuda-me a buscar a Tua presença com a mesma constância da viúva, não por orgulho, mas porque reconheço que Tu és o único Juiz justo e amoroso. Que minha oração diária seja o reflexo da minha confiança inabalável em Teu cuidado.', 1),
('243d1c60-a9d2-4d3e-8c92-44f1e2546c66', 'Individual', 'Senhor, sonda o meu coração e traz à luz tudo o que tenho tentado esconder sob justificativas. Dá-me a coragem de Davi para confessar meus erros sem rodeios e a humildade para aceitar a correção da Tua Palavra. Que a minha lealdade a Ti seja demonstrada na integridade das minhas ações e na sinceridade do meu arrependimento. Amém.', 1),
('246b72ad-e2cb-4738-98d7-07397be2c6a6', 'Individual', 'Senhor, ajuda-me a ser a mesma pessoa tanto no público quanto no secreto. Que a consciência da Tua presença seja suficiente para me sustentar em toda tentação, garantindo que meu coração permaneça puro e fiel à Tua vontade, acima de qualquer conveniência momentânea.', 1),
('24bce7c0-4b93-45d1-b7fc-e785dbcc03ff', 'Individual', 'Senhor, ajuda-me a ser uma pessoa cuja vida seja marcada pela coerência e pela fidelidade prática. Que as minhas ações diárias confirmem o meu compromisso com aqueles que o Senhor confiou aos meus cuidados, para que o meu caráter seja um reflexo do Teu zelo e da Tua verdade. Amém.', 1),
('24bfb230-955a-4d72-a2a1-9fd9f3c52f28', 'Pai', 'Senhor, dá-nos um coração corajoso como o de Sadraque, Mesaque e Abednego. Ajuda-nos a sermos fiéis a Ti, mesmo quando ninguém mais estiver olhando.', 1),
('24bfb230-955a-4d72-a2a1-9fd9f3c52f28', 'Filho', 'Deus, tira de mim o medo de ser diferente. Que eu tenha forças para escolher o que é certo, mesmo quando estiver sozinho.', 2),
('24bfb230-955a-4d72-a2a1-9fd9f3c52f28', 'Juntos', 'Pai, que nossa família seja um exemplo de obediência. Que a Tua vontade seja sempre maior que a pressão ao nosso redor.', 3),
('24db7077-8452-4c73-a066-bc757e0c8e9d', 'Pai', 'Papai do Céu, obrigado porque Tu sempre nos esperas de braços abertos. Ajuda-nos a ter um coração bondoso para pedir desculpas quando erramos.', 1),
('24db7077-8452-4c73-a066-bc757e0c8e9d', 'Filho', 'Querido Deus, às vezes eu erro, mas quero sempre voltar para perto do Senhor. Obrigado porque o Teu amor é maior do que qualquer erro meu.', 2),
('24db7077-8452-4c73-a066-bc757e0c8e9d', 'Juntos', 'Obrigado, Pai, pela Tua alegria em nos receber. Que a nossa casa seja sempre um lugar de perdão e abraços sinceros.', 3),
('24df8fc3-4208-49c7-a010-4a35d2ceee44', 'Pai', 'Papai do céu, ensina nosso filho a observar as maravilhas da Tua criação. Dá a ele um coração atento para aprender com os exemplos que o Senhor deixou na natureza.', 1),
('24df8fc3-4208-49c7-a010-4a35d2ceee44', 'Filho', 'Querido Deus, ajuda-me a ser cuidadoso com minhas coisas. Ensina-me a ser sábio e não ter pressa em minhas escolhas.', 2),
('24df8fc3-4208-49c7-a010-4a35d2ceee44', 'Juntos', 'Obrigado, Senhor, por nos ensinar o valor da prudência. Que a nossa família caminhe sempre com a Tua sabedoria, hoje e sempre!', 3),
('255afafe-492c-476b-bfac-5b1df333341c', 'Pai', 'Senhor, ensina nosso filho a caminhar pela Tua Palavra, mesmo quando o caminho não parece claro. Que a nossa casa seja um lugar de obediência constante ao Teu chamado.', 1),
('255afafe-492c-476b-bfac-5b1df333341c', 'Filho', 'Pai do céu, ajuda-me a ter a coragem de Abraão para fazer escolhas certas. Que eu não dependa de ver tudo antes, mas que eu confie plenamente no Teu guia.', 2),
('255afafe-492c-476b-bfac-5b1df333341c', 'Juntos', 'Deus, firmamos nossa vida na Tua fidelidade eterna. Que nossa família siga os Teus passos com fé verdadeira e obediência sincera, hoje e sempre.', 3),
('258d6e16-8548-4609-b836-4e9a4f0e8744', 'Pai', 'Papai do Céu, obrigado pelos filhos que o Senhor nos deu. Dá-nos sabedoria para ensinar o caminho certo com amor.', 1),
('258d6e16-8548-4609-b836-4e9a4f0e8744', 'Filho', 'Obrigado, Deus, pelo meu pai e pela minha mãe que cuidam de mim. Ajuda-me a respeitá-los todos os dias.', 2),
('258d6e16-8548-4609-b836-4e9a4f0e8744', 'Juntos', 'Senhor, abençoa nossa casa para que o respeito e o amor sejam sempre nossos guias. Amém!', 3),
('25977ad1-b271-4db2-bd32-dcb57d67583e', 'Pai', 'Senhor, ajuda-nos a ser firmes em nossos valores, mesmo quando o caminho mais fácil parece ser o mais atraente. Dá-nos a coragem de Daniel para permanecer fiéis a Ti.', 1),
('25977ad1-b271-4db2-bd32-dcb57d67583e', 'Filho', 'Pai do céu, ajuda-me a fazer escolhas certas na escola e com meus amigos. Que eu sempre prefira o Teu caminho, mesmo quando me sentir sozinho.', 2),
('25977ad1-b271-4db2-bd32-dcb57d67583e', 'Juntos', 'Obrigado, Deus, por estares conosco em cada decisão. Ajuda nossa família a crescer na Tua sabedoria e a manter sempre o nosso coração puro.', 3),
('25cf110c-429e-4b86-9bb8-eb88f31d8a89', 'Pai', 'Pai do céu, ajuda-nos a ter um coração humilde como o deste filho. Que possamos sempre correr de volta para Ti quando errarmos.', 1),
('25cf110c-429e-4b86-9bb8-eb88f31d8a89', 'Filho', 'Papai do céu, perdoa as vezes que desobedeci ou fiz coisas erradas. Obrigado porque Tu sempre me amas e me recebes de braços abertos.', 2),
('25cf110c-429e-4b86-9bb8-eb88f31d8a89', 'Juntos', 'Obrigado, Deus, pelo Teu amor que não desiste de nós. Que nossa casa seja sempre um lugar de perdão e alegria.', 3),
('25d86472-2a0f-4f35-96af-269f5fc3d026', 'Individual', 'Senhor, ajuda-me a discernir o que é essencial da obra que colocaste em minhas mãos. Dá-me a coragem de Neemias para recusar as distrações que tentam desviar meu olhar do meu dever. Que meu foco permaneça inabalável e minha fidelidade seja evidente em cada tarefa deste dia. Amém.', 1),
('2642aff0-f90a-46b7-8b45-5b3673019470', 'Pai', 'Senhor, ensina meu filho a valorizar a verdade acima do orgulho. Que ele tenha coragem para voltar sempre para os Teus caminhos.', 1),
('2642aff0-f90a-46b7-8b45-5b3673019470', 'Filho', 'Pai, perdoa as vezes que tentei esconder meus erros. Ajuda-me a ser sincero e a escolher o caminho certo sempre.', 2),
('2642aff0-f90a-46b7-8b45-5b3673019470', 'Juntos', 'Deus, ajuda-nos a viver com honestidade em nosso lar. Que a Tua graça seja o nosso norte todos os dias.', 3),
('2714d066-1e17-4adb-a337-9d377783669b', 'Individual', 'Senhor, peço sabedoria para filtrar as vozes que permito perto de mim. Dá-me amigos que não busquem apenas me agradar, mas que me ajudem a ser mais parecido com a Tua vontade. Que minhas amizades sejam forjas de santidade e que eu, da mesma forma, possa ser um instrumento de correção e encorajamento na vida daqueles que me cercam. Amém.', 1),
('273b69ad-7cf9-4d8a-bb8f-7c0db110b8f3', 'Individual', 'Senhor, perdoa-me pela rigidez do meu coração que muitas vezes prefere o conforto à obediência. Ensina-me a enxergar as feridas alheias sem desviar o olhar e concede-me um espírito generoso, capaz de sacrificar o meu tempo e os meus recursos sem buscar recompensa. Que minha fé se traduza em ações concretas de cuidado, honrando o sacrifício que Tu fizeste por mim. Amém.', 1),
('278475ae-6126-48f7-b51b-6f4ba6059f74', 'Individual', 'Senhor, reconheço que a falta de vigilância sobre as pequenas escolhas pode desviar meu coração de Ti. Dá-me a clareza para enxergar onde tenho cedido terreno e a coragem necessária para estabelecer limites firmes. Que o Teu Espírito governe os meus desejos e ações, mantendo minha integridade intacta para Te servir com total lealdade. Amém.', 1),
('29506ce1-ee27-4bd7-a7c5-9ef3c3466756', 'Pai', 'Papai do céu, ajuda o meu filho a ter um coração obediente como o de Daniel. Que ele saiba escolher o que é bom e agradável a Ti.', 1),
('29506ce1-ee27-4bd7-a7c5-9ef3c3466756', 'Filho', 'Querido Deus, ajuda-me a ser forte e calmo na hora de dizer não. Quero cuidar do meu corpo e fazer sempre o que o Senhor gosta.', 2),
('29506ce1-ee27-4bd7-a7c5-9ef3c3466756', 'Juntos', 'Obrigado, Senhor, por nos ensinar a viver com moderação. Que nossa família siga sempre o Teu caminho com alegria e verdade.', 3),
('29c389e6-0d3f-4478-bbb3-42dc84e02225', 'Pai', 'Pai, ajuda-me a guiar o meu filho a escolher amigos que amam a Tua Palavra. Que nossa casa seja sempre um lugar de boas companhias.', 1),
('29c389e6-0d3f-4478-bbb3-42dc84e02225', 'Filho', 'Papai do Céu, coloca amigos bondosos no meu caminho. Quero aprender coisas boas com eles todos os dias.', 2),
('29c389e6-0d3f-4478-bbb3-42dc84e02225', 'Juntos', 'Senhor, obrigado por sermos amigos um do outro e por termos o Teu amor nos unindo. Amém.', 3),
('29ead731-8089-4c8d-8302-44f2ea5821d0', 'Pai', 'Senhor, ajuda-nos a lembrar de Tua grandeza mesmo quando enfrentamos dificuldades. Que nossa casa seja um lugar onde o Teu louvor sempre encontra espaço.', 1),
('29ead731-8089-4c8d-8302-44f2ea5821d0', 'Filho', 'Deus, tira o foco dos meus problemas e me ajuda a enxergar as coisas boas. Ensina-me a usar minhas palavras para abençoar quem está ao meu lado.', 2),
('29ead731-8089-4c8d-8302-44f2ea5821d0', 'Juntos', 'Pai, obrigado por estares conosco em todo o tempo. Que o nosso louvor seja a marca da nossa família hoje e sempre.', 3),
('2a8c1c0c-7699-40d7-b3ad-8411e63a5844', 'Pai', 'Pai do Céu, ajuda-nos a ensinar aos nossos filhos a importância de ouvir com atenção. Que nossos corações estejam sempre voltados para Ti.', 1),
('2a8c1c0c-7699-40d7-b3ad-8411e63a5844', 'Filho', 'Querido Deus, ajuda-me a ser obediente e a parar o que estou fazendo para ouvir quem me ama. Ensina meus olhos a olharem sempre para o bem.', 2),
('2a8c1c0c-7699-40d7-b3ad-8411e63a5844', 'Juntos', 'Senhor, juntos queremos aprender a focar no que é importante. Que nossa família siga sempre o Teu caminho com alegria e obediência.', 3),
('2b3ae018-dec4-49a7-88d9-d60b9049b978', 'Individual', 'Senhor, reconheço que tudo o que tenho vem da Tua mão. Quando o chão me faltar, ajuda-me a não vacilar na fé, mas a prostrar-me diante da Tua soberania com um coração sincero. Que a minha adoração seja o meu testemunho de fidelidade, mesmo que eu nada possua.', 1),
('2b579ff7-02af-43f4-92e7-5f06c947d12f', 'Pai', 'Senhor, ajuda-me a ser um exemplo de perdão e portas abertas para meus filhos. Que meu coração seja sempre um lugar seguro para a verdade deles.', 1),
('2b579ff7-02af-43f4-92e7-5f06c947d12f', 'Filho', 'Pai do Céu, dá-me coragem para admitir quando erro e força para voltar atrás. Que eu nunca prefira o orgulho ao caminho de volta para Ti.', 2),
('2b579ff7-02af-43f4-92e7-5f06c947d12f', 'Juntos', 'Deus, ensina-nos a valorizar a honestidade acima da reputação. Que nossa família seja firme na verdade e sempre pronta para o recomeço.', 3),
('2bd78f31-15aa-4962-bb72-a89aba0d82b7', 'Pai', 'Senhor, obrigado por nos ensinar que o descanso é um presente Teu. Ajuda-nos a entender que o limite é um sinal de sabedoria.', 1),
('2bd78f31-15aa-4962-bb72-a89aba0d82b7', 'Filho', 'Pai do céu, tira de mim a ansiedade de querer fazer tudo o tempo todo. Ensina-me a confiar que Tu cuidas de mim em cada etapa.', 2),
('2bd78f31-15aa-4962-bb72-a89aba0d82b7', 'Juntos', 'Que a Tua paz nos guie a vivermos com moderação e obediência. Amém.', 3),
('2c44ed79-d6de-4532-a6ad-9c41e832af10', 'Individual', 'Senhor, perdoa-me pelas vezes em que recebi Tua misericórdia e segui meu caminho como se fosse mérito próprio. Que meu coração não se torne insensível pela rotina. Ajuda-me a enxergar Tua mão em cada detalhe deste dia e concede-me um espírito humilde, que sempre retorna aos Teus pés para agradecer antes de prosseguir.', 1),
('2caed807-a3c5-4421-a1fd-65ed0266d997', 'Pai', 'Senhor, ajuda-nos a ser firmes em Tua Palavra. Que o medo não nos impeça de seguir o Teu caminho.', 1),
('2caed807-a3c5-4421-a1fd-65ed0266d997', 'Filho', 'Deus, dá-me coragem para escolher a verdade na escola, mesmo quando for difícil ser diferente. Ajuda-me a confiar em Ti.', 2),
('2caed807-a3c5-4421-a1fd-65ed0266d997', 'Juntos', 'Pai, caminharemos juntos na Tua direção. Que a Tua presença nos torne fortes e destemidos todos os dias.', 3),
('2cbdbe8b-6496-466c-90dd-7585ee12b7d3', 'Individual', 'Senhor, perdoa-me pela minha insensibilidade. Muitas vezes recebo a Tua bondade e sigo meu caminho como se tudo fosse mérito meu. Ensina-me a ser como aquele samaritano: que eu sempre volte aos Teus pés para Te honrar. Que meu coração seja grato não apenas pelo que recebo, mas pelo privilégio de estar perto de Ti. Amém.', 1),
('2cc10378-8f7b-4df7-800d-ad52d25fab21', 'Pai', 'Papai do Céu, ajuda-nos a ensinar aos nossos filhos a importância de ouvir a Tua voz acima de qualquer outra. Que a nossa família caminhe sempre com obediência e respeito às Tuas leis.', 1),
('2cc10378-8f7b-4df7-800d-ad52d25fab21', 'Filho', 'Querido Deus, ajuda-me a ser corajoso como Daniel. Ensina-me a escolher o que agrada o Senhor, mesmo quando todos ao redor fizerem escolhas diferentes.', 2),
('2cc10378-8f7b-4df7-800d-ad52d25fab21', 'Juntos', 'Obrigado, Senhor, por cuidar de nós. Que a nossa obediência seja a nossa força hoje e sempre.', 3),
('2cd4d47a-d8d0-425f-aa9c-47e68a96ab5d', 'Pai', 'Senhor, ajuda meu filho a discernir amizades que trazem sabedoria e luz. Que ele encontre companheiros que temam ao Senhor.', 1),
('2cd4d47a-d8d0-425f-aa9c-47e68a96ab5d', 'Filho', 'Pai, peço que me tornes um amigo leal como Jônatas. Que eu saiba escolher quem anda comigo conforme a Tua verdade.', 2),
('2cd4d47a-d8d0-425f-aa9c-47e68a96ab5d', 'Juntos', 'Que a nossa família valorize relacionamentos que honram a Deus. Que nossas amizades sempre nos aproximem do Teu bom propósito.', 3),
('2ce9aba7-d197-4b5f-94f7-7da15d0e7de2', 'Pai', 'Senhor, ajuda-me a ser um exemplo de coragem para meu filho. Que possamos confiar em Ti acima de qualquer medo.', 1),
('2ce9aba7-d197-4b5f-94f7-7da15d0e7de2', 'Filho', 'Deus, dá-me forças para ser fiel aos teus mandamentos, mesmo quando for difícil ser diferente na escola. Ajuda-me a escolher o que é certo.', 2),
('2ce9aba7-d197-4b5f-94f7-7da15d0e7de2', 'Juntos', 'Pai, reafirmamos hoje que o nosso serviço pertence somente a Ti. Que a nossa vida glorifique Teu nome em todo tempo.', 3),
('2d380c25-c04b-45e7-b025-2655b573ff47', 'Pai', 'Pai, ajuda-nos a ser sempre um porto seguro para nossos filhos. Que nosso abraço reflita o Teu amor sem medidas.', 1),
('2d380c25-c04b-45e7-b025-2655b573ff47', 'Filho', 'Papai do Céu, perdoa quando eu erro ou desobedeço. Quero sempre correr para perto de Ti e da minha família.', 2),
('2d380c25-c04b-45e7-b025-2655b573ff47', 'Juntos', 'Obrigado porque o Teu amor nunca acaba. Ensina-nos a perdoar uns aos outros todos os dias!', 3),
('2d71c9fc-66de-47c3-a5ef-aceee8e2bcca', 'Pai', 'Senhor, dá-nos a coragem de ser fiéis à Tua palavra em todos os lugares. Ajuda nossos filhos a terem convicções firmes.', 1),
('2d71c9fc-66de-47c3-a5ef-aceee8e2bcca', 'Filho', 'Deus, dá-me forças para não fazer o que é errado só porque os outros estão fazendo. Que o meu caráter seja sempre verdadeiro.', 2),
('2d71c9fc-66de-47c3-a5ef-aceee8e2bcca', 'Juntos', 'Pai, que a nossa família permaneça de pé diante de qualquer pressão. Que a Tua glória seja sempre a nossa maior meta.', 3),
('2d762370-4532-422c-b810-c749a2cc24d4', 'Pai', 'Senhor, ajuda-nos a discernir o que é essencial. Dá sabedoria para manter o foco no que é eterno.', 1),
('2d762370-4532-422c-b810-c749a2cc24d4', 'Filho', 'Pai, quero aprender a dizer não às distrações. Ajuda-me a concluir as tarefas que começarei hoje.', 2),
('2d762370-4532-422c-b810-c749a2cc24d4', 'Juntos', 'Que nossa família permaneça fiel à missão que nos deste. Que nada nos distraia do Teu chamado.', 3),
('2d7b82dc-c9b0-4f6b-a6ba-15590988603b', 'Individual', 'Senhor, perdoa-me por tantas vezes buscar posições que não me cabem. Que o Teu exemplo de lavar os pés dos discípulos transforme meu coração, tornando-me um servo atento e fiel. Capacita-me a ver o próximo com o mesmo olhar de cuidado que Tu tiveste, removendo de mim todo orgulho. Amém.', 1),
('2dd1d69c-0b49-44cd-a312-d0379fed1f38', 'Pai', 'Senhor, ajuda-me a ensinar meus filhos a escolherem sempre o Teu caminho. Que nossas vidas sejam exemplos de obediência e amor a Ti.', 1),
('2dd1d69c-0b49-44cd-a312-d0379fed1f38', 'Filho', 'Papai do Céu, por favor, me ajude a escolher o que é bom. Quero sempre seguir os Teus passos e obedecer com alegria.', 2),
('2dd1d69c-0b49-44cd-a312-d0379fed1f38', 'Juntos', 'Obrigado por nos dar a liberdade de escolher a vida ao Teu lado. Queremos caminhar contigo todos os dias, amém!', 3),
('2e2a2969-8bd4-4a14-8353-98fec685c514', 'Pai', 'Pai, ensina-nos a cuidar uns dos outros com um coração generoso. Que sejamos como Boaz, sempre prontos para abençoar quem está perto.', 1),
('2e2a2969-8bd4-4a14-8353-98fec685c514', 'Filho', 'Papai do céu, ajuda-me a ser bondoso com meus amigos e irmãos hoje. Quero alegrar o Teu coração com gestos de amor.', 2),
('2e2a2969-8bd4-4a14-8353-98fec685c514', 'Juntos', 'Obrigado, Senhor, pela Tua bondade que nunca falha. Que nossa casa seja um lugar cheio de gentileza e alegria.', 3),
('2eaa1093-6f1a-4e6d-af83-aa0747eaee49', 'Individual', 'Senhor, ajuda-me a ser alguém cujo caráter não depende do clima das circunstâncias. Concede-me a força de Rute para manter a fidelidade e a retidão, honrando meus compromissos mesmo quando o custo é alto. Que a minha vida seja um testemunho de integridade, provada pelo meu agir e não apenas pelo meu falar. Amém.', 1);
